            "Global temperatures have risen approximately 1.2°C above pre-industrial levels. The Paris Agreement targets limiting warming to 1.5°C, but current trajectories suggest 2.5-3°C by 2100.",
            "Renewable energy capacity surpassed coal for the first time in 2024. Solar and wind costs have dropped 90% in the past decade, making them the cheapest new electricity sources.",
            "Key mitigation strategies include carbon capture, electrification of transport, methane reduction, reforestation, and sustainable agriculture practices.",
        ],
    };

    [Description("Searches the web for information on a given query. Returns a list of relevant search result snippets.")]
    public static string[] SearchWeb(
        [Description("The search query to look up on the web")] string query)
    {
        foreach (var (key, results) in SimulatedResults)
        {
            if (query.Contains(key, StringComparison.OrdinalIgnoreCase))
            {
                return results;
            }
        }

        return
        [
            $"Search result 1 for '{query}': This topic is actively being researched with new developments emerging regularly.",
            $"Search result 2 for '{query}': Experts suggest this area will see significant advances in the coming years.",
            $"Search result 3 for '{query}': Recent studies indicate growing interest and investment in this field.",
        ];
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

public sealed class NoteTakingTool
{
    private readonly List<Note> _notes = [];

    public IReadOnlyList<Note> Notes => _notes;

    [Description("Saves a research note with a category and content. Use this to organize findings during research.")]
    public string SaveNote(
        [Description("The category for this note (e.g., 'key_finding', 'statistic', 'open_question')")] string category,
        [Description("The content of the note to save")] string content)
    {
        var note = new Note(category, content, DateTime.UtcNow);
        _notes.Add(note);
        return $"Note saved under '{category}' (total notes: {_notes.Count})";
    }

    [Description("Retrieves all saved research notes, optionally filtered by category.")]
    public string GetNotes(
        [Description("Optional category filter. Pass empty string to get all notes.")] string category = "")
    {
        var filtered = string.IsNullOrWhiteSpace(category)
            ? _notes
            : _notes.Where(n => n.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

        if (filtered.Count == 0)
        {
            return "No notes found.";
        }

        return string.Join("\n", filtered.Select((n, i) =>
            $"[{i + 1}] [{n.Category}] {n.Content}"));
    }
}

public sealed record Note(string Category, string Content, DateTime Timestamp);

