toolArgs.old_str:
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;
using ResearchAgent.Tools;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the AI:ApiKey configuration value or OPENAI_API_KEY environment variable.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, new OpenAI.OpenAIClient(apiKey)));

var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();

// Set up tools
var noteTool = new NoteTakingTool();
var tools = new AIFunction[]
{
    AIFunctionFactory.Create(WebSearchTool.SearchWeb),
    AIFunctionFactory.Create(noteTool.SaveNote),
    AIFunctionFactory.Create(noteTool.GetNotes),
};

// Configure the agent
var agent = new ChatClientAgent(chatClient,
    "You are a research assistant. Your job is to research a topic thoroughly by:\n" +
    "1. Searching the web for relevant information using the SearchWeb tool\n" +
    "2. Saving important findings as notes using the SaveNote tool (use categories like 'key_finding', 'statistic', 'challenge', 'opportunity')\n" +
    "3. After gathering enough information, retrieve your notes with GetNotes and provide a comprehensive summary\n\n" +
    "Be thorough: search for multiple aspects of the topic (overview, recent developments, challenges, applications).",
    tools);

// Get topic from user
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine() ?? "quantum computing";
}

Console.WriteLine($"\nResearching: {topic}");
Console.WriteLine(new string('─', 50));

var history = new List<ChatMessage>
{
    new(ChatRole.User,
        $"Research the following topic and provide a comprehensive summary: {topic}")
};

var options = new AgentInvokeOptions
{
    MaximumIterations = 10,
};

// Run the agent and stream output
Console.WriteLine("\n[Agent working...]\n");

await foreach (var message in agent.InvokeStreamingAsync(history, options))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
    {
        Console.Write(message.Text);
    }
}

Console.WriteLine("\n");
Console.WriteLine(new string('─', 50));

// Display collected notes
if (noteTool.Notes.Count > 0)
{
    Console.WriteLine($"\n📝 Research Notes Collected ({noteTool.Notes.Count}):");
    foreach (var note in noteTool.Notes)
    {
        Console.WriteLine($"  [{note.Category}] {note.Content}");
    }
}

Console.WriteLine("\nResearch complete.");

