 var noteTool = new NoteTakingTool();
 var tools = new List<AITool>
 {
     AIFunctionFactory.Create(WebSearchTool.SearchWeb),
     AIFunctionFactory.Create(noteTool.SaveNote),
     AIFunctionFactory.Create(noteTool.GetNotes),
 };

 const string instructions = """
     You are a research assistant. Your job is to research a topic thoroughly by:
     1. Searching the web for relevant information using the SearchWeb tool
     2. Saving important findings as notes using the SaveNote tool (use categories like 'key_finding', 'statistic', 'challenge', 'opportunity')
     3. After gathering enough information, retrieve your notes with GetNotes and provide a comprehensive summary

     Be thorough: search for multiple aspects of the topic (overview, recent developments, challenges, applications).
     Always save at least 3 notes before summarizing.
     """;

 // Create the agent with tools
 var agent = new ChatClientAgent(
     chatClient,
     name: "ResearchAgent",
     description: "An AI agent that researches topics using web search and note-taking",
     instructions: instructions,
     tools: tools);

 // Get topic from user
 Console.WriteLine("╔══════════════════════════════════════╗");
 Console.WriteLine("║       AI Research Agent              ║");
 Console.WriteLine("╚══════════════════════════════════════╝");
 Console.WriteLine();

 string topic;
 if (args.Length > 0)
 {
     topic = string.Join(' ', args);
 }
 else
 {
     Console.Write("Enter a research topic: ");
     topic = Console.ReadLine() ?? "quantum computing";
 }

 Console.WriteLine($"\nResearching: {topic}");
 Console.WriteLine(new string('─', 50));
 Console.WriteLine("\n[Agent working...]\n");

 // Create a session and run the agent with streaming
 var session = await agent.CreateSessionAsync("research");

 await foreach (var update in agent.RunStreamingAsync(
     $"Research the following topic and provide a comprehensive summary: {topic}",
     session))
 {
     if (!string.IsNullOrEmpty(update.Text))
     {
         Console.Write(update.Text);
     }
 }

 Console.WriteLine("\n");
 Console.WriteLine(new string('─', 50));

 // Display collected notes
 if (noteTool.Notes.Count > 0)
 {
     Console.WriteLine($"\n📝 Research Notes Collected ({noteTool.Notes.Count}):");
     foreach (var note in noteTool.Notes)
     {
         Console.WriteLine($"  [{note.Category}] {note.Content}");
     }
 }

 Console.WriteLine("\nResearch complete.");
